"use client";

import { Lock, Key } from "lucide-react";
import { useSearchParams, useRouter } from "next/navigation";
import { useEffect, useState } from "react";

export default function ResetPasswordPage() {
  const router = useRouter();
  const searchParams = useSearchParams();
  const email = searchParams.get("email");

  const [otp, setOtp] = useState("");
  const [password, setPassword] = useState("");
  const [message, setMessage] = useState(null);
  const [loading, setLoading] = useState(false);

  // 🔐 Block logged in users
  useEffect(() => {
    const token = localStorage.getItem("accessToken");
    if (token) {
      router.replace("/");
    }

    if (!email) {
      router.replace("/forgot-password");
    }
  }, []);

  const handleReset = async (e) => {
    e.preventDefault();

    if (!otp || !password) {
      setMessage({ type: "error", text: "All fields required" });
      return;
    }

    if (password.length < 8) {
      setMessage({ type: "error", text: "Password must be 8 characters" });
      return;
    }

    try {
      setLoading(true);
      setMessage(null);

      const res = await fetch("http://localhost:5000/user/resetPassword", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          email,
          otp,
          newPassword: password,
        }),
      });

      const data = await res.json();

      if (!res.ok) throw new Error(data.message);

      setMessage({
        type: "success",
        text: "Password reset successful",
      });

      setTimeout(() => {
        router.push("/login");
      }, 1500);
    } catch (err) {
      setMessage({
        type: "error",
        text: err.message || "Reset failed",
      });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex justify-center items-center bg-gray-50">
      <div className="bg-white p-10 rounded-2xl shadow-xl w-[420px]">
        <h1 className="text-2xl font-semibold mb-2 text-center">
          Reset Password
        </h1>

        <p className="text-sm text-gray-600 mb-5 text-center">
          Enter OTP and new password
        </p>

        <form onSubmit={handleReset} className="space-y-4">
          <div className="relative">
            <Key className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400" />
            <input
              placeholder="Enter OTP"
              className="pl-10 h-11 border rounded-lg w-full"
              value={otp}
              onChange={(e) => setOtp(e.target.value)}
            />
          </div>

          <div className="relative">
            <Lock className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400" />
            <input
              type="password"
              placeholder="New Password"
              className="pl-10 h-11 border rounded-lg w-full"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
            />
          </div>

          <button
            type="submit"
            disabled={loading}
            className="w-full bg-blue-500 h-11 text-white rounded-lg hover:bg-blue-600 disabled:opacity-60"
          >
            {loading ? "Resetting..." : "Reset Password"}
          </button>
        </form>

        {message && (
          <p
            className={`mt-4 text-sm text-center ${
              message.type === "error" ? "text-red-500" : "text-green-600"
            }`}
          >
            {message.text}
          </p>
        )}
      </div>
    </div>
  );
}
